
import React, { useState, useEffect } from 'react';
import PinView from "./PinControls/PinView.js";
import Layout from "./Layout.js";

/**
 *  This component holds the Live Debugger UI (determined by the board chosen by the user). This component requires two data parameters (pinData, deviceData), which hold
 * the current states of the analog/digital pins (pinData) and the states of onboard sensors (deviceData). This component also accepts a serial communication method, which should be
 * (queryBoard(selection, data)), to query the board for new data or update the boards pins/sensors.
 * @param {*} param0 
 */
function DataDisplay({pinData, serialCom, deviceData}) {
    
    const [pin, selectPin] = useState({Type: 'START'});
    
    useEffect(
        () => {
            if(pin)
            {
                if(pin.Type == 'LED_PLOT' || pin.Type == 'LED_UNPLOT' || pin.Type=='START')
                {
                    serialCom("PINS");
                }
                else
                {
                    serialCom(pin.Type);
                }
            }
        },
        [pin.Type]//For sensors that require delays/refreshed data we need to set a TimeInterval for continously querying the sensor data
    );

    //Remove sensor selection styling
    document.querySelectorAll(".active_sensor").forEach(element =>{
            //Style
            element.setAttribute("fill", element.getAttribute("fill") == "white" ? "black" : "white");

            //Remove styling marker
            element.classList.remove("active_sensor");
        }
    );

    if(pin.Type !== "START" && pin.Type !== "NA" && pin.Type !== "PINS")
    {
        //Style
        document.getElementById(pin.Type + "_rect").setAttribute("fill", "black");
        document.getElementById(pin.Type + "_text").setAttribute("fill", "white");
        
        //Add marker to remove styling when deselected
        document.getElementById(pin.Type + "_rect").classList.add("active_sensor");
        document.getElementById(pin.Type + "_text").classList.add("active_sensor");
    }

    let data = {
                    Type: "START",
                    Analog: "NA",//Verify the pin is present
                    Analog_Id: "START",
                    Digital: "NA",//Verify the pin is present
                    Digital_Id: "START",
                    Pwm:  0,
                    Pwm_Id: "START"
                };  
    let disabled = false;
    if(pin)
    {
        if(pinData !== null)
        {//May need to also check if deviceData has been set
            try{
                //TODO update for switch statement?
                if(pin.Type == "PINS")
                {
                    data = {
                        Type: "PINS",
                        Analog: pin.Analog in pinData ? pinData[pin.Analog] : "NA",//Verify the pin is present
                        Analog_Id: pin.Analog,
                        Digital: pin.Digital in pinData ? pinData[pin.Digital] : "NA",//Verify the pin is present
                        Digital_Id: pin.Digital,
                        Pwm: pin.Pwm in deviceData.pwm ? deviceData.pwm[pin.Pwm] : 0,
                        Pwm_Id: pin.Pwm
                    };
                }
                else if(pin.Type == "MOTION")
                {
                    data = {
                        Type: "MOTION",
                        X: deviceData.motion.X,
                        Y: deviceData.motion.Y,
                        Z: deviceData.motion.Z,
                        Strength: deviceData.motion.Strength,
                    };
                    disabled = true;
                }
                else if(pin.Type == "MAGNET")
                {
                    data = {
                        Type: "MAGNET",
                        X: deviceData.compass.X,
                        Y: deviceData.compass.Y,
                        Z: deviceData.compass.Z,
                        Strength: deviceData.compass.Strength,
                    };
                    disabled = true;
                }
                else if(pin.Type == "COMPASS")
                {
                    data = {
                        Type: "COMPASS",
                        Heading: deviceData.compass.Compass_Head,
                    };
                    disabled = true;
                }
                else if(pin.Type == "ROTATE")
                {
                    data = {
                        Type: "ROTATE",
                        Pitch: deviceData.rotate.Pitch,
                        Roll: deviceData.rotate.Roll,
                    };
                    disabled = true;
                }
                else if(pin.Type == "LIGHT")
                {
                    data = {
                        Type: "LIGHT",
                        Light : deviceData.light
                    };
                    disabled = true;
                }
                else if(pin.Type == "TEMP")
                {
                    data = {
                        Type: "TEMP",
                        Temp: deviceData.temp
                    };
                }
                else if(pin.Type == "GESTURE")
                {
                    data = {
                        Type: "GESTURE",
                        Gesture: deviceData.gesture
                    };
                }
            }
            catch(e){
                console.log("Pin [" + pin + "] has no Data!");
            }
        }
        
    }

  return (
      <>    
        <svg 
            width={"100%"} 
            viewBox="0 0 1440 1024"
        >
            <PinView data={data} update={serialCom} /> 
            <Layout pinData={pinData} data={data} deviceData={deviceData} disabled={disabled} serialCom={serialCom} trigger={selectPin}/>;
    
        </svg>
     </>

    );
}

export default DataDisplay