
import * as React from "react"

function LedArray({ x, y, trigger, row=5, col=5, spacing=45, led_settings}) {
  let matrix = [];
  
  for(let r = 0; r < row; r++)
  {
    for(let c = 0; c < col; c++)
    {
      matrix.push(<rect fill={led_settings[r][c] == 0 ? "white" : "red"} style={{cursor:'pointer'}} onClick={() => {trigger( led_settings[r][c] == 0 ? "LED_PLOT" : "LED_UNPLOT", { x: c, y: r} )}} class="clickable" x={x + (c * spacing)} y={y + (r * spacing)} width={15} height={30}>
                    <title>
                      ({c},{r})
                    </title>  
                  </rect>);;
    }
  }
  return(
      <>
        {matrix}
      </>
    )
}

export default LedArray