import React from "react"
import AnalogPin from "./Pins/AnalogPin.js"
import DigitalPin from "./Pins/DigitalPin.js"
import PwmPin from "./Pins/PwmPin.js"
import Motion from "./Sensors/Motion.js"
import GenericReading from "./Sensors/GenericReading.js"

//pins [{type, number, callback}]
function PinView({data, update}) {
    
    let display = "";
    if(data.Type == "PINS" || data.Type == "START")
    {
      let pwmActive = false;
      if(data.Pwm > 0 && data.Pwm < 255)
      {
        pwmActive = true;
      }    
      display =<>
                  <AnalogPin x={0} y={0} id={data.Analog_Id} value={data.Analog} pwmActive={pwmActive}/>
                  <DigitalPin x={480} y={0} id={data.Digital_Id} value={data.Digital} update={update} pwmActive={pwmActive}/>
                  <PwmPin  x={960} y={0} id={data.Pwm_Id} value={data.Pwm} update={update} key={data.Pwm_Id} />
              </>;
    }
    else if(data.Type == "MOTION" || data.Type == "MAGNET")
    {
      display= <>
                  <Motion x={0} y={0} reading={data} />
                </>;
    }
    else if(data.Type == "TEMP")
    {
      display= <>
                  <GenericReading display_x ={5} display_width={400} display_text="Temperature"  reading_text={data.Temp} reading_width={75} color={2}/>
                </>;
    }
    else if(data.Type == "LIGHT")
    {
      display= <>
                  <GenericReading display_x ={5} display_width={175} display_text="Light"  reading_text={data.Light} reading_width={290} color={2}/>
                </>;
    }
    else if(data.Type == "COMPASS")
    {
      display= <>
                  <GenericReading display_x ={5} display_width={550} display_text="Compass Heading"  reading_text={data.Heading} reading_width={125} color={2}/>
                </>;
    }
    else if(data.Type == "GESTURE")
    {
      display= <>
                  <GenericReading display_x ={5} display_width={250} display_text="Gesture"  reading_text={data.Gesture} reading_width={350} color={2}/>
                </>;
    }
    else if(data.Type == "ROTATE")
    {
      display= <>
                  <GenericReading display_x ={5} display_width={170} display_text="Pitch"  reading_text={data.Pitch} reading_width={310} color={2}/>
                  <GenericReading display_x ={500} display_width={130} display_text="Roll"  reading_text={data.Roll} reading_width={350} color={3}/>
                </>;
    }
    return(
      <>
      <svg width={1440} height={133} viewBox="0 0 1440 133" fill="none" x={0} y={0}>
        <rect fill="var(--bgColor2)"  width={480} height={115} x={0} y={0}/>
        <rect fill="var(--bgColor3)"  width={480} height={115} x={480} y={0}/>
        <rect fill="var(--bgColor4)"  width={480} height={115} x={960} y={0} />
        {display}
      </svg>
      </>
    )
}

export default PinView