
import * as React from "react";

function GenericSensor({x, y, text_x, text_y, trigger, display, type}) {

  function select(){
    document.getElementById(type + "_rect").setAttribute("fill", "black");
    document.getElementById(type + "_text").setAttribute("fill", "white");
  }

function deselect(){
  //Verify sensor isn't selected before removing styling
  if(!document.getElementById(type + "_rect").classList.contains("active_sensor"))
  {
    document.getElementById(type + "_rect").setAttribute("fill", "white");
    document.getElementById(type + "_text").setAttribute("fill", "black");
  }
}

  return(
      <>
        <rect id={type + "_rect"} fill= "white" x={x} y={y} width={350} height={50} stroke="black" strokeWidth="0.36" />
        <text id={type  + "_text"} x={text_x} y={text_y} fill="black" style={{fontSize:"3em", fontWeight:"bold"}}>
            {display}
            <title>{display}</title>
        </text>
        <rect fill= "transparent" onMouseEnter={() => {select()}} onMouseLeave={() => {deselect()}}  style={{cursor:'pointer'}} onClick={() => {trigger({Type: type})}} x={x} y={y} width={350} height={50}/>
      </>
    )
}

export default GenericSensor