import * as React from "react";
import PinCircle from "./PinControls/Pins/PinCircle.js";
import Board from "./Board.js";
import PinKey from "./PinControls/PinKey.js";
import LedArray from "./PinControls/Actuators/LedArray.js";
import GenericSensor from "./PinControls/Sensors/GenericSensor.js";

function Layout({pinData, trigger, data, disabled, serialCom, deviceData}) {
  /***
   * 
   * 
   * This code block sets digitalValues -> an array that keeps track of a pin's current setting (Low: 0, High: 1, High-In: 2, PWM-ON: 3, Disabled: 4), 
   * this is passed to the  PinCircle component as a setting prop, which determines the pin's color.
   * This is all hardcoded for the the Circuit Playground Classic's pin/sensor ids.
   */
  //TODO Convert to use object/key pair and then use ids for the keys down below     <g transform="rotate(90, 102.029, 102.5125)">
      return (
          <>
            {/* Animations for the pin's current state (Low, High, High-In, PWM-ON, Disabled*/}
            <defs>  
                <linearGradient id="pinGradientHigh" x1="0%" y1="0%" x2="100%" y2="100%" > 
                    <stop offset="0%" stopColor="red">
                        <animate attributeName="stop-color" values="black;red;black" dur="1.5s" repeatCount="indefinite"></animate>
                    </stop>
                </linearGradient>
                <linearGradient id="pinGradientHighIn" x1="0%" y1="0%" x2="100%" y2="100%" > 
                    <stop offset="0%" stopColor="yellow">
                        <animate attributeName="stop-color" values="black;yellow;black" dur="1.5s" repeatCount="indefinite"></animate>
                    </stop>
                </linearGradient>
                <linearGradient id="pinGradientPwmOn" x1="0%" y1="0%" x2="100%" y2="100%" > 
                    <stop offset="0%" stopColor="#66CCEE">
                        <animate attributeName="stop-color" values="black;#66CCEE;black" dur="1.5s" repeatCount="indefinite"></animate>
                    </stop>
                </linearGradient>
                <linearGradient id="pinDisabled" x1="0%" y1="0%" x2="100%" y2="100%" > 
                    <stop offset="0%" stopColor="grey">
                        <animate attributeName="stop-color" values="grey" dur="1.5s" repeatCount="indefinite"></animate>
                    </stop>
                </linearGradient>
                <linearGradient id="cant_control" x1="0%" y1="0%" x2="100%" y2="100%" > 
                    <stop offset="0%" stopColor="#d4ae1b">
                        <animate attributeName="stop-color" values="#d4ae1b" dur="1.5s" repeatCount="indefinite"></animate>
                    </stop>
                </linearGradient>
               
              </defs>
            
            {/* Ensure the Pin/Sensor Selectors are placed on top of the microcontroller */}
            <Board width={575} height={600} x={420.08} y={125} />

            {/*Pin Holes */}
            <PinCircle analog="A0" digital="D0" pwm="D0" x={485.5} y={510} trigger={trigger} setting={0} radius={22}/>
            <PinCircle analog="A1" digital="D1" pwm="D1" x={592.5} y={510} trigger={trigger} setting={0} radius={22} />
            <PinCircle analog="A2" digital="D2" pwm="D2" x={711.5} y={510} trigger={trigger} setting={0} radius={22}/>
            
            {/* LED Array */}
            <LedArray x={615} y={240} trigger={serialCom} data={data} led_settings={deviceData.led_array}/>

            {/* On Board Sensors*/}
            <GenericSensor x={1040} y={180} text_x={1060} text_y={220} display="Accelerometer" type="MOTION" trigger={trigger}/>
            <GenericSensor x={1040} y={235} text_x={1060} text_y={275} display="Rotation" type="ROTATE" trigger={trigger}/>
            <GenericSensor x={1040} y={290} text_x={1060} text_y={330} display="Gesture" type="GESTURE" trigger={trigger}/>    
            <GenericSensor x={1040} y={345} text_x={1060} text_y={385} display="Compass" type="COMPASS" trigger={trigger}/>
            <GenericSensor x={1040} y={400} text_x={1060} text_y={440} display="Magnetic Force" type="MAGNET" trigger={trigger}/>
            <GenericSensor x={1040} y={455} text_x={1060} text_y={495} display="Temperature" type="TEMP" trigger={trigger}/>
            <GenericSensor x={1040} y={510} text_x={1060} text_y={550} display="Light" type="LIGHT" trigger={trigger}/>

            <PinKey x={0} y={115} /> 
         </>
    
    )
}

export default Layout