
import * as React from "react"

function GenericReading({display_x, display_width, display_text, reading_text, reading_width, color=2}) {

  let value = <>
                 <rect fill="#000000" style={{fillOpacity:0.75}} x={display_x + display_width} y={5} width={reading_width} height={105} />
                 <text fill="white" x={display_x + display_width + 10} y={83.5} style={{fontWeight:"bolder", fontSize:"3em"}}>{"NA"}</text>
                </>;
  if(reading_text !== "NA" && reading_text !== "START")
  {
    value = <> 
                <text fill="black" x={display_x + display_width + 10} y={83.5} style={{fontWeight:"bolder", fontSize:"4em"}}>{reading_text}</text>
            </>;
  }
  return(
      <>
      {/* Reading */}
        <rect width={display_width + reading_width + 10} height={115} fill={"var(--bgColor" +color +")"} x={display_x} y={0}></rect>
        <rect fill="#FFFFFF" width={reading_width} height={105}  x={display_x + display_width + 5} y={ 5} />
        <rect fill={"var(--bgColor" +color +")"} width={110} height={115} x={display_x} y={0}/>
        <text  x={display_x} y={82.5}  fill={"var(--fontColor" +color +")"} style={{fontFamily: "Roboto" ,fontWeight:"bolder", fontSize: "5em" }}>{display_text}</text>
        {value}
      </>
    )
}

export default GenericReading
